# 示例2：安全文件操作类 - 带dry-run模式和危险路径检查
# 适用于：删除文件、批量修改等不可逆操作

class SafeFileOperation:
    def __init__(self, dry_run: bool = True):
        self.dry_run = dry_run
        self.requires_confirmation = ['delete', 'remove', 'rm']

    def safe_delete(self, filepath: str, backup: bool = True):
        path = Path(filepath).resolve()
        if not path.exists():
            return {'success': False, 'error': '文件不存在'}

        # 危险路径检查
        dangerous_patterns = ['/etc/', '/usr/', '/bin/', '/sbin/']
        for pattern in dangerous_patterns:
            if str(path).startswith(pattern):
                raise PermissionError(f"危险路径禁止删除: {path}")

        # 创建备份
        backup_path = None
        if backup and path.is_file():
            backup_path = Path(str(path) + '.backup')
            if not self.dry_run:
                shutil.copy2(path, backup_path)

        # 执行删除
        if not self.dry_run:
            path.unlink()
            if backup_path:
                backup_path.unlink()  # 确认后才删除备份

        return {'success': True, 'dry_run': self.dry_run, 'path': str(path)}

