// server/src/routes/tasks.ts - 任务路由
import { Router, Request, Response } from 'express';
import { db } from '../models/database';

export const tasksRouter = Router();

// 获取所有任务
tasksRouter.get('/', (_req: Request, res: Response) => {
  try {
    const tasks = db.prepare(`
      SELECT id, title, description, priority, 
             completed, created_at as createdAt, updated_at as updatedAt
      FROM tasks 
      ORDER BY created_at DESC
    `).all();

    res.json({ success: true, data: tasks });
  } catch (error) {
    console.error('获取任务失败:', error);
    res.status(500).json({ success: false, error: '获取任务失败' });
  }
});

// 创建新任务
tasksRouter.post('/', (req: Request, res: Response) => {
  const { title, description, priority = 'medium' } = req.body;

  // 输入验证
  if (!title || typeof title !== 'string' || title.trim().length === 0) {
    return res.status(400).json({ 
      success: false, 
      error: '任务标题不能为空' 
    });
  }

  if (title.length > 100) {
    return res.status(400).json({ 
      success: false, 
      error: '任务标题不能超过100个字符' 
    });
  }

  const validPriorities = ['low', 'medium', 'high'];
  if (!validPriorities.includes(priority)) {
    return res.status(400).json({ 
      success: false, 
      error: '优先级必须是 low, medium 或 high' 
    });
  }

  try {
    const result = db.prepare(`
      INSERT INTO tasks (title, description, priority) 
      VALUES (?, ?, ?)
    `).run(title.trim(), description || '', priority);

    const newTask = db.prepare(`
      SELECT id, title, description, priority, 
             completed, created_at as createdAt, updated_at as updatedAt
      FROM tasks WHERE id = ?
    `).get(result.lastInsertRowid);

    res.status(201).json({ success: true, data: newTask });
  } catch (error) {
    console.error('创建任务失败:', error);
    res.status(500).json({ success: false, error: '创建任务失败' });
  }
});

// 更新任务状态
tasksRouter.patch('/:id', (req: Request, res: Response) => {
  const { id } = req.params;
  const { completed } = req.body;

  if (typeof completed !== 'boolean') {
    return res.status(400).json({ 
      success: false, 
      error: 'completed必须是布尔值' 
    });
  }

  try {
    const result = db.prepare(`
      UPDATE tasks 
      SET completed = ?, updated_at = datetime('now') 
      WHERE id = ?
    `).run(completed ? 1 : 0, id);

    if (result.changes === 0) {
      return res.status(404).json({ success: false, error: '任务不存在' });
    }

    const updatedTask = db.prepare(`
      SELECT id, title, description, priority, 
             completed, created_at as createdAt, updated_at as updatedAt
      FROM tasks WHERE id = ?
    `).get(id);

    res.json({ success: true, data: updatedTask });
  } catch (error) {
    console.error('更新任务失败:', error);
    res.status(500).json({ success: false, error: '更新任务失败' });
  }
});

// 删除任务
tasksRouter.delete('/:id', (req: Request, res: Response) => {
  const { id } = req.params;

  try {
    const result = db.prepare('DELETE FROM tasks WHERE id = ?').run(id);

    if (result.changes === 0) {
      return res.status(404).json({ success: false, error: '任务不存在' });
    }

    res.json({ success: true, message: '任务删除成功' });
  } catch (error) {
    console.error('删除任务失败:', error);
    res.status(500).json({ success: false, error: '删除任务失败' });
  }
});


