// client/src/services/api.ts - API服务层
import { Task, ApiResponse, CreateTaskDto } from '../types';

const API_BASE_URL = 'http://localhost:3001/api';

class TaskApiService {
  private async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<ApiResponse<T>> {
    try {
      const response = await fetch(`${API_BASE_URL}${endpoint}`, {
        headers: {
          'Content-Type': 'application/json',
        },
        ...options,
      });

      const data = await response.json();

      if (!response.ok) {
        return { 
          success: false, 
          error: data.error || `请求失败: ${response.status}` 
        };
      }

      return { success: true, data };
    } catch (error) {
      console.error('API请求错误:', error);
      return { 
        success: false, 
        error: error instanceof Error ? error.message : '网络请求失败' 
      };
    }
  }

  async getTasks(): Promise<ApiResponse<Task[]>> {
    return this.request<Task[]>('/tasks');
  }

  async createTask(task: CreateTaskDto): Promise<ApiResponse<Task>> {
    return this.request<Task>('/tasks', {
      method: 'POST',
      body: JSON.stringify(task),
    });
  }

  async toggleTask(id: number, completed: boolean): Promise<ApiResponse<Task>> {
    return this.request<Task>(`/tasks/${id}`, {
      method: 'PATCH',
      body: JSON.stringify({ completed }),
    });
  }

  async deleteTask(id: number): Promise<ApiResponse<void>> {
    return this.request<void>(`/tasks/${id}`, {
      method: 'DELETE',
    });
  }
}

export const taskApi = new TaskApiService();


