// client/src/components/TaskForm.tsx - 任务表单组件
import React, { useState } from 'react';
import { CreateTaskDto } from '../types';

interface TaskFormProps {
  onSubmit: (task: CreateTaskDto) => Promise<void>;
  isLoading: boolean;
}

export const TaskForm: React.FC<TaskFormProps> = ({ onSubmit, isLoading }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<CreateTaskDto['priority']>('medium');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!title.trim()) {
      alert('请输入任务标题');
      return;
    }

    await onSubmit({ 
      title: title.trim(), 
      description: description.trim() || undefined, 
      priority 
    });

    // 重置表单
    setTitle('');
    setDescription('');
    setPriority('medium');
  };

  return (
    <form onSubmit={handleSubmit} className="task-form">
      <div className="form-group">
        <label htmlFor="title">任务标题 *</label>
        <input
          id="title"
