// client/src/App.tsx - 主应用组件
import React, { useState, useEffect, useCallback } from 'react';
import { TaskForm } from './components/TaskForm';
import { TaskList } from './components/TaskList';
import { taskApi } from './services/api';
import { Task, CreateTaskDto } from './types';
import './App.css';

function App() {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // 加载任务列表
  const loadTasks = useCallback(async () => {
    setIsLoading(true);
    setError(null);

    const result = await taskApi.getTasks();

    if (result.success && result.data) {
      setTasks(result.data);
    } else {
      setError(result.error || '加载任务失败');
    }

    setIsLoading(false);
  }, []);

  // 初始化加载
  useEffect(() => {
    loadTasks();
  }, [loadTasks]);

  // 创建任务
  const handleCreateTask = async (task: CreateTaskDto) => {
    setIsLoading(true);

    const result = await taskApi.createTask(task);

    if (result.success && result.data) {
      setTasks((prev) => [result.data!, ...prev]);
    } else {
      alert(result.error || '创建任务失败');
    }

    setIsLoading(false);
  };

  // 切换完成状态
  const handleToggleTask = async (id: number, completed: boolean) => {
    // 乐观更新：立即更新UI
    setTasks((prev) =>
      prev.map((task) =>
        task.id === id ? { ...task, completed } : task
      )
    );

    const result = await taskApi.toggleTask(id, completed);

    if (!result.success) {
      // 回滚
      setTasks((prev) =>
        prev.map((task) =>
          task.id === id ? { ...task, completed: !completed } : task
        )
      );
      alert(result.error || '更新任务失败');
    }
  };

  // 删除任务
  const handleDeleteTask = async (id: number) => {
    // 保存当前状态用于回滚
    const previousTasks = tasks;

    // 乐观更新
    setTasks((prev) => prev.filter((task) => task.id !== id));

    const result = await taskApi.deleteTask(id);

    if (!result.success) {
      // 回滚
      setTasks(previousTasks);
      alert(result.error || '删除任务失败');
    }
  };

  // 分离已完成和未完成任务
  const activeTasks = tasks.filter((task) => !task.completed);
  const completedTasks = tasks.filter((task) => task.completed);

  return (
    <div className="app">
      <header className="app-header">
        <h1>📋 任务管理器</h1>
        <p className="subtitle">使用 Codex CLI 构建的全栈应用示例</p>
      </header>

      <main className="app-main">
        {error && (
          <div className="error-banner">
            ⚠️ {error}
            <button onClick={loadTasks}>重试</button>
          </div>
        )}

        <section className="form-section">
          <h2>添加新任务</h2>
          <TaskForm onSubmit={handleCreateTask} isLoading={isLoading} />
        </section>

        <section className="list-section">
          <h2>
            进行中的任务 
            <span className="count-badge">{activeTasks.length}</span>
          </h2>
          <TaskList
            tasks={activeTasks}
            onToggle={handleToggleTask}
            onDelete={handleDeleteTask}
            isLoading={isLoading}
          />
        </section>

        {completedTasks.length > 0 && (
          <section className="list-section completed-section">
            <h2>
              已完成 
              <span className="count-badge">{completedTasks.length}</span>
            </h2>
            <TaskList
              tasks={completedTasks}
              onToggle={handleToggleTask}
              onDelete={handleDeleteTask}
              isLoading={isLoading}
            />
          </section>
        )}
      </main>
    </div>
  );
}

export default App;


