# Python 示例：成本监控与分析器
import json
from datetime import datetime
from typing import List, Dict

class CostMonitor:
    """AI API成本监控系统"""

    def __init__(self, budget_limit=100):
        self.budget_limit = budget_limit  # 月度预算（美元）
        self.history = []
        self.cost_per_1k_tokens = 0.003  # 假设费率

    def log_request(self, input_tokens: int, output_tokens: int, 
                   model: str, task_type: str):
        """记录每次API调用"""
        cost = (input_tokens + output_tokens) / 1000 * self.cost_per_1k_tokens
        entry = {
            "timestamp": datetime.now().isoformat(),
            "input_tokens": input_tokens,
            "output_tokens": output_tokens,
            "total_tokens": input_tokens + output_tokens,
            "cost": round(cost, 4),
            "model": model,
            "task_type": task_type
        }
        self.history.append(entry)

        # 检查预算
        total_cost = self.get_total_cost()
        if total_cost > self.budget_limit * 0.8:
            print(f"⚠️ 警告：已消耗 {total_cost:.2f}/${self.budget_limit}")

        return cost

    def get_total_cost(self) -> float:
        """计算总花费"""
        return sum(e["cost"] for e in self.history)

    def get_cost_by_task_type(self) -> Dict[str, float]:
        """按任务类型分析成本"""
        result = {}
        for entry in self.history:
            task = entry["task_type"]
            result[task] = result.get(task, 0) + entry["cost"]
        return result

    def get_cost_by_model(self) -> Dict[str, float]:
        """按模型分析成本"""
        result = {}
        for entry in self.history:
            model = entry["model"]
            result[model] = result.get(model, 0) + entry["cost"]
        return result

    def generate_report(self) -> str:
        """生成成本报告"""
        report = f"""
========== 成本分析报告 ==========
总花费: ${self.get_total_cost():.4f}
预算使用: {self.get_total_cost()/self.budget_limit*100:.1f}%
请求次数: {len(self.history)}

按任务类型分布:
{json.dumps(self.get_cost_by_task_type(), indent=2)}

按模型分布:
{json.dumps(self.get_cost_by_model(), indent=2)}
================================
"""
        return report

# 使用示例
monitor = CostMonitor(budget_limit=50)

# 模拟API调用记录
monitor.log_request(1500, 200, "gpt-4", "代码补全")
monitor.log_request(3000, 500, "gpt-4", "代码审查")
monitor.log_request(800, 100, "gpt-3.5-turbo", "格式化")

print(monitor.generate_report())
