def validate_username(username: str) -> str:
    """验证用户名：长度3-20个字符"""
    if not username:
        raise ValueError("用户名不能为空")
    if len(username) < 3:
        raise ValueError("用户名至少3个字符")
    if len(username) > 20:
        raise ValueError("用户名最多20个字符")
