## 代码示例

### 示例 1

```python
// ========== 后端入口文件 (server/src/index.ts) ==========
import express, { Request, Response, NextFunction } from 'express';
import cors from 'cors';

const app = express();
const PORT = process.env.PORT || 3001;

// CORS配置：允许前端开发服务器访问
app.use(cors({
  origin: 'http://localhost:3000',
  credentials: true
}));

// JSON解析中间件
app.use(express.json());

// 健康检查端点
app.get('/api/health', (_req: Request, res: Response) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// 错误处理中间件（放在所有路由之后）
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('服务器错误:', err.message);
  res.status(500).json({ 
    success: false,
    error: '服务器内部错误'
  });
});

app.listen(PORT, () => {
  console.log(`🚀 服务器运行在 http://localhost:${PORT}`);
});
```

### 示例 2

```python
// ========== 任务路由处理 (server/src/routes/tasks.ts) ==========
import { Router, Request, Response } from 'express';
import { db } from '../models/database';

export const tasksRouter = Router();

// 获取所有任务
tasksRouter.get('/', (_req: Request, res: Response) => {
  try {
    const tasks = db.prepare(`
      SELECT id, title, description, priority, 
             completed, created_at as createdAt
      FROM tasks ORDER BY created_at DESC
    `).all();
    res.json({ success: true, data: tasks });
  } catch (error) {
    res.status(500).json({ success: false, error: '获取任务失败' });
  }
});

// 创建新任务（包含输入验证）
tasksRouter.post('/', (req: Request, res: Response) => {
  const { title, description, priority = 'medium' } = req.body;

  // 验证：标题必填且不超过100字符
  if (!title?.trim() || title.length > 100) {
    return res.status(400).json({ 
      success: false, 
      error: '任务标题不能为空且不超过100字符' 
    });
  }

  // 验证：优先级枚举值
  const validPriorities = ['low', 'medium', 'high'];
  if (!validPriorities.includes(priority)) {
    return res.status(400).json({ 
      success: false, 
      error: '优先级必须是 low, medium 或 high' 
    });
  }

  // 插入数据库并返回新记录
  const result = db.prepare(`
    INSERT INTO tasks (title, description, priority) VALUES (?, ?, ?)
  `).run(title.trim(), description || '', priority);

  const newTask = db.prepare('SELECT * FROM tasks WHERE id = ?').get(result.lastInsertRowid);
  res.status(201).json({ success: true, data: newTask });
});

// 切换任务完成状态
tasksRouter.patch('/:id/toggle', (req: Request, res: Response) => {
  const { id } = req.params;
  const { completed } = req.body;

  const result = db.prepare(`
    UPDATE tasks SET completed = ?, updated_at = datetime('now') WHERE id = ?
  `).run(completed ? 1 : 0, id);

  if (result.changes === 0) {
    return res.status(404).json({ success: false, error: '任务不存在' });
  }

  const updatedTask = db.prepare('SELECT * FROM tasks WHERE id = ?').get(id);
  res.json({ success: true, data: updatedTask });
});

// 删除任务
tasksRouter.delete('/:id', (req: Request, res: Response) => {
  const { id } = req.params;
  const result = db.prepare('DELETE FROM tasks WHERE id = ?').run(id);

  if (result.changes === 0) {
    return res.status(404).json({ success: false, error: '任务不存在' });
  }

  res.json({ success: true, message: '任务已删除' });
});
```

### 示例 3

```python
// ========== 前端API服务层 (client/src/services/api.ts) ==========
import { Task, ApiResponse, CreateTaskDto } from '../types';

const API_BASE = 'http://localhost:3001/api';

class TaskApiService {
  // 通用请求方法，统一处理错误和响应格式
  private async request<T>(url: string, options: RequestInit = {}): Promise<ApiResponse<T>> {
    try {
      const response = await fetch(`${API_BASE}${url}`, {
        headers: { 'Content-Type': 'application/json' },
        ...options,
      });

      const data = await response.json();

      if (!response.ok) {
        return { success: false, error: data.error || `HTTP ${response.status}` };
      }

      return { success: true, data };
    } catch (error) {
      // 网络错误、CORS错误等会进入这里
      console.error('API请求失败:', error);
      return { success: false, error: '网络连接失败，请检查服务器是否运行' };
    }
  }

  // 获取所有任务
  async getTasks(): Promise<ApiResponse<Task[]>> {
    return this.request<Task[]>('/tasks');
  }

  // 创建任务
  async createTask(task: CreateTaskDto): Promise<ApiResponse<Task>> {
    return this.request<Task>('/tasks', {
      method: 'POST',
      body: JSON.stringify(task),
    });
  }

  // 切换完成状态
  async toggleTask(id: number, completed: boolean): Promise<ApiResponse<Task>> {
    return this.request<Task>(`/tasks/${id}/toggle`, {
      method: 'PATCH',
      body: JSON.stringify({ completed }),
    });
  }

  // 删除任务
  async deleteTask(id: number): Promise<ApiResponse<void>> {
    return this.request<void>(`/tasks/${id}`, {
      method: 'DELETE',
    });
  }
}

export const taskApi = new TaskApiService();
```



## 常见错误

- 前后端分离开发时忘记配置CORS，导致浏览器阻止跨域请求
- 使用SQLite时多个并发写入导致数据库锁定错误，应改用PostgreSQL或添加重试机制
- 前端直接修改state而非使用setState函数，导致UI不更新
- API请求缺少错误处理，用户体验差，应展示友好的错误提示
- 未进行输入验证就存入数据库，可能导致XSS或SQL注入风险
- TypeScript类型定义与后端实际返回不一致，应使用共享类型包
- 乐观更新失败后未回滚状态，导致UI与服务器数据不同步
- 在useEffect中使用async函数但未正确处理依赖项，导致无限循环请求


## 最佳实践

- 采用API契约驱动开发：先定义接口规范，再分别开发前后端，保持类型一致性
- 前后端独立部署：前端构建后通过nginx服务静态文件，后端通过环境变量配置API地址
- 乐观更新 + 回滚机制：先更新UI提升用户体验，API失败时回滚状态并提示用户
- 统一的错误响应格式：所有API返回{success, data?, error?}结构，前端统一处理
- 输入验证双重保障：前端即时验证改善体验，后端严格验证保障安全
- 组件职责单一化：TaskForm只负责表单输入，TaskList只负责列表渲染，App组件协调状态
- 善用TypeScript类型推断：明确接口定义，充分利用IDE补全和类型检查
- Codex CLI使用技巧：提供完整上下文、分步骤请求、始终review生成的代码

