import { Task, ApiResponse, CreateTaskDto } from '../types';

const API_BASE = 'http://localhost:3001/api';

class TaskApiService {
  // 通用请求方法，统一处理错误和响应格式
  private async request<T>(url: string, options: RequestInit = {}): Promise<ApiResponse<T>> {
    try {
      const response = await fetch(`${API_BASE}${url}`, {
        headers: { 'Content-Type': 'application/json' },
        ...options,
      });

      const data = await response.json();

      if (!response.ok) {
        return { success: false, error: data.error || `HTTP ${response.status}` };
      }

      return { success: true, data };
    } catch (error) {
      // 网络错误、CORS错误等会进入这里
      console.error('API请求失败:', error);
      return { success: false, error: '网络连接失败，请检查服务器是否运行' };
    }
  }

  // 获取所有任务
  async getTasks(): Promise<ApiResponse<Task[]>> {
    return this.request<Task[]>('/tasks');
  }

  // 创建任务
  async createTask(task: CreateTaskDto): Promise<ApiResponse<Task>> {
    return this.request<Task>('/tasks', {
      method: 'POST',
      body: JSON.stringify(task),
    });
  }

  // 切换完成状态
  async toggleTask(id: number, completed: boolean): Promise<ApiResponse<Task>> {
    return this.request<Task>(`/tasks/${id}/toggle`, {
      method: 'PATCH',
      body: JSON.stringify({ completed }),
    });
  }

  // 删除任务
  async deleteTask(id: number): Promise<ApiResponse<void>> {
    return this.request<void>(`/tasks/${id}`, {
      method: 'DELETE',
    });
  }
}

