"""交互式CLI工具 - Click库示例"""

import click
from dataclasses import dataclass

@dataclass
class Task:
    id: int
    title: str
    done: bool = False

# 任务列表（内存存储）
tasks = []
next_id = 1

@click.group()
def cli():
    """任务管理器CLI"""
    pass

@cli.command()
@click.option('-t', '--title', prompt=True, help='任务标题')
def add(title):
    """添加新任务"""
    global next_id
    task = Task(id=next_id, title=title)
    tasks.append(task)
    next_id += 1
    click.echo(click.style(f'✓ 任务已添加 (ID: {task.id})', fg='green'))

@cli.command()
@click.option('-p', '--pending', is_flag=True, help='仅显示待办任务')
def list(pending):
    """列出所有任务"""
    filtered = [t for t in tasks if not (pending and t.done)]
    for t in filtered:
        status = '✓' if t.done else '○'
        color = 'green' if t.done else 'yellow'
        click.echo(f"[{click.style(status, fg=color)}] {t.id}. {t.title}")

@cli.command()
@click.argument('task_id', type=int)
def done(task_id):
    """标记任务完成"""
    for t in tasks:
        if t.id == task_id:
            t.done = True
            click.echo(click.style(f'✓ 任务 #{task_id} 已完成', fg='green'))
            return
    click.echo(click.style(f'✗ 未找到任务 #{task_id}', fg='red'), err=True)

if __name__ == '__main__':
    cli()

