/*
 * @fileOverview Express 服务器入口模块
 * @description 负责应用初始化、中间件配置和路由挂载
 * @author DevTeam
 * @version 3.0.0
 */

import express from 'express';
import { config } from './config';
import { authRouter } from './routes/auth';
import { userRouter } from './routes/users';
import { errorHandler } from './middleware/errorHandler';

/**
 * 创建并配置 Express 应用
 * @returns {express.Application} 配置好的 Express 应用实例
 * @example
 * const app = createApp();
 * app.listen(3000);
 */
export function createApp() {
  const app = express();

  // 中间件配置
  app.use(express.json());
  app.use(express.urlencoded({ extended: true }));

  // 健康检查端点
  app.get('/health', (req, res) => {
    res.json({ status: 'ok', timestamp: new Date().toISOString() });
  });

  // API 路由
  app.use('/api/auth', authRouter);
  app.use('/api/users', userRouter);

  // 错误处理中间件（必须最后注册）
  app.use(errorHandler);

  return app;
}

/**
 * 启动服务器
 * @async
 * @param {number} [port] - 服务器端口，默认使用配置中的端口
 * @returns {Promise<http.Server>} HTTP 服务器实例
 */
export async function startServer(port?: number) {
  const app = createApp();
  const portToUse = port || config.port || 3000;

  return new Promise((resolve) => {
    const server = app.listen(portToUse, () => {
      console.log(`🚀 服务器运行在 http://localhost:${portToUse}`);
      resolve(server);
    });
  });
}

