# 文件位置：.codex/workflows/release-checklist.yml

name: "release-checklist"
description: "发布前检查清单工作流"
trigger:
  - pattern: "codex release"
    description: "触发完整发布检查"

steps:
  - name: "version-bump"
    prompt: |
      分析当前Git提交，生成符合语义化版本(-semver)的版本号建议。
      查看 CHANGELOG.md 了解当前版本。
      如果有 BREAKING CHANGE，major版本+1。
      如果有新功能，minor版本+1。
      如果只是修复bug，patch版本+1。
    action: "suggest_version"

  - name: "changelog-update"
    prompt: |
      根据Git提交历史自动生成更新CHANGELOG.md的条目。
      使用conventional commits格式分组：
      - Features
      - Bug Fixes  
      - Performance Improvements
      - Breaking Changes
    action: "update_changelog"
    depends_on: ["version-bump"]

  - name: "test-verification"
    prompt: "运行完整的测试套件并生成覆盖率报告"
    action: "run_tests"
    timeout: "300s"
    depends_on: ["changelog-update"]

  - name: "security-scan"
    prompt: "运行依赖安全扫描，检查已知漏洞"
    action: "run_security_scan"
    depends_on: ["test-verification"]

  - name: "generate-release-notes"
    prompt: |
      基于CHANGELOG和提交历史，生成GitHub Release的说明文档。
      格式要求：
      - 突出显示Breaking Changes
      - 包含升级指南（如果有）
      - 链接相关的Issue和PR
    output: "RELEASE_NOTES.md"

