// JavaScript 示例：智能模型选择器
class ModelSelector {
    constructor() {
        // 模型配置：能力 vs 成本权衡
        this.models = {
            'codex-fast': { 
                cost: 0.001,  // 每千token价格
                speed: 'fast',
                capabilities: ['autocomplete', 'simple-fix']
            },
            'codex-standard': { 
                cost: 0.01, 
                speed: 'medium',
                capabilities: ['code-gen', 'explain', 'review']
            },
            'codex-pro': { 
                cost: 0.05, 
                speed: 'slow',
                capabilities: ['complex-debug', 'architecture', 'refactor']
            }
        };
    }

    // 评估任务复杂度
    analyzeComplexity(task) {
        const complexPatterns = [
            /架构设计|重构|性能优化/i,
            /调试|排查|疑难问题/i,
            /跨文件|多模块/i
        ];

        const isComplex = complexPatterns.some(p => p.test(task));
        const isLong = task.length > 500;

        if (isComplex || isLong) return 'complex';
        if (task.length > 100) return 'medium';
        return 'simple';
    }

    // 选择最优模型
    selectModel(task, budget = 'medium') {
        const complexity = this.analyzeComplexity(task);

        // 简单任务 -> 快速模型（节省成本）
        if (complexity === 'simple') {
            return { 
                model: 'codex-fast', 
                reason: '简单任务，使用快速模型节省成本'
            };
        }

        // 中等任务 -> 标准模型（平衡）
        if (complexity === 'medium') {
            return { 
                model: 'codex-standard', 
                reason: '中等复杂度，使用标准模型'
            };
        }

        // 复杂任务 -> 专业模型（保证质量）
        return { 
            model: 'codex-pro', 
            reason: '复杂任务，使用高性能模型确保质量'
        };
    }

    // 估算任务成本
    estimateCost(task, model) {
        const tokens = Math.ceil(task.length / 4); // 粗略估算
        return (tokens / 1000) * this.models[model].cost;
    }
}

// 使用示例
const selector = new ModelSelector();

const tasks = [
    "修复这个语法错误",
    "解释这段递归函数的逻辑",
    "设计一个微服务架构来处理高并发"
];

tasks.forEach(task => {
    const { model, reason } = selector.selectModel(task);
    const cost = selector.estimateCost(task, model);
    console.log(`任务: "${task.substring(0, 20)}..."`);
    console.log(`  -> 选择: ${model} | 估算成本: $${cost.toFixed(4)}`);
    console.log(`  -> 原因: ${reason}\n`);
});

```



## 常见错误

- 将整个代码仓库上传给AI，消耗大量不必要的Token
- 对所有任务使用最高级别的模型，造成资源浪费
- 没有建立成本监控机制，直到月底账单才发现超支
- 忽略缓存机制，每次请求都重新获取相同信息
- 在长对话中持续累积上下文，导致响应越来越慢
- 提示词过于冗长，包含大量重复或无关信息
- 使用代码格式不佳的文件（大量注释、空行），增加token消耗
- 没有定期清理会话历史，缓存过期数据占用空间


## 最佳实践

- 使用精准文件路径而非整个目录，只向AI提供相关代码
- 建立任务难度分级制度，配套相应的模型选择策略（如80/15/5法则）
- 部署实时成本监控和告警系统，及时发现异常消耗
- 实现本地缓存层，对重复请求复用历史答案
- 定期清理会话历史，避免上下文无限膨胀
- 优化代码文件结构，去除无效注释和空行后再提交分析
- 会话过长时，将进度总结后重启新会话，比持续发送长上下文更经济
- 批量处理相似任务，减少API调用次数和总开销
- 精简提示词表达，去除冗余描述，只保留核心需求
- 建立成本分析报告机制，追踪各项目、功能的成本分布，针对性优化高消耗环节

