# Python 示例：实现简单的Token缓存机制
import hashlib
from datetime import datetime, timedelta

class TokenCache:
    """Token缓存管理器，避免重复API调用"""

    def __init__(self, ttl_hours=24):
        self.cache = {}
        self.ttl = timedelta(hours=ttl_hours)

    def _make_key(self, prompt: str, model: str) -> str:
        """生成缓存键：结合提示词和模型"""
        content = f"{model}:{prompt}"
        return hashlib.md5(content.encode()).hexdigest()

    def get(self, prompt: str, model: str):
        """获取缓存的响应"""
        key = self._make_key(prompt, model)
        if key in self.cache:
            result, timestamp = self.cache[key]
            if datetime.now() - timestamp < self.ttl:
                print(f"✅ 缓存命中，节省Token")
                return result
            else:
                del self.cache[key]  # 过期则删除
        return None

    def set(self, prompt: str, model: str, response: str):
        """保存响应到缓存"""
        key = self._make_key(prompt, model)
        self.cache[key] = (response, datetime.now())

    def get_stats(self):
        """获取缓存统计"""
        return {
            "cached_items": len(self.cache),
            "total_tokens_saved": len(self.cache) * 500  # 估算
        }

# 使用示例
cache = TokenCache(ttl_hours=48)

# 检查缓存
cached = cache.get("如何反转链表", "gpt-4")
if cached:
    print(cached)
else:
    # 模拟API调用
    result = "使用双指针反转链表..."
    cache.set("如何反转链表", "gpt-4", result)
    print(result)

print(cache.get_stats())

```

